const resp = $.steps.scrapeUrl.response || {};
const data = resp.data || {};
const md = data.markdown || '';
const metadata = data.metadata || {};
const url = $.input.url;

const prompt = `You are an expert SEO consultant. Perform a comprehensive on-page SEO audit of the following website.

WEBSITE URL: ${url}

PAGE METADATA:
- Title: ${metadata.title || 'Not found'}
- Description: ${metadata.description || 'Not found'}
- Language: ${metadata.language || 'Not found'}

PAGE CONTENT:
${md.slice(0, 8000)}

ANALYZE THE FOLLOWING SEO FACTORS:
1. Title tag - length, keyword usage, uniqueness
2. Meta description - length, call to action, keyword usage
3. Heading structure - H1, H2, H3 hierarchy
4. Content quality - length, keyword density, readability
5. Internal/external links
6. Image optimization (alt tags mentioned in markdown)
7. URL structure
8. Mobile-friendliness indicators
9. Content freshness signals
10. Schema/structured data indicators

Return ONLY valid JSON:
{
  "overallScore": 75,
  "grade": "B",
  "titleTag": { "score": 80, "current": "...", "recommendation": "..." },
  "metaDescription": { "score": 70, "current": "...", "recommendation": "..." },
  "headings": { "score": 65, "findings": "...", "recommendation": "..." },
  "contentQuality": { "score": 80, "wordCount": 0, "findings": "...", "recommendation": "..." },
  "links": { "score": 70, "findings": "...", "recommendation": "..." },
  "images": { "score": 60, "findings": "...", "recommendation": "..." },
  "technicalSeo": { "score": 75, "findings": "...", "recommendation": "..." },
  "topIssues": ["<issue1>", "<issue2>", "<issue3>"],
  "quickWins": ["<win1>", "<win2>", "<win3>"],
  "summary": "<executive summary>"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { overallScore: 0, grade: 'N/A', summary: raw, topIssues: [], quickWins: [] }; }

const ai = $.steps.parseAI.output || {};
const url = $.input.url;
const date = new Date().toISOString().split('T')[0];

const gradeColor = ai.overallScore >= 80 ? '#28a745' : ai.overallScore >= 60 ? '#ffc107' : '#dc3545';

let html = '<div style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto;">';
html += '<h1 style="color: #333;">SEO Audit Report</h1>';
html += '<p><strong>URL:</strong> <a href="' + url + '">' + url + '</a></p>';
html += '<p><strong>Date:</strong> ' + date + '</p>';
html += '<div style="background: ' + gradeColor + '; color: white; padding: 20px; border-radius: 8px; text-align: center; margin: 20px 0;">';
html += '<h2 style="margin: 0; color: white;">Overall Score: ' + (ai.overallScore || 'N/A') + '/100 (Grade: ' + (ai.grade || 'N/A') + ')</h2>';
html += '</div>';

html += '<h2>Executive Summary</h2><p>' + (ai.summary || '') + '</p>';

const sections = ['titleTag', 'metaDescription', 'headings', 'contentQuality', 'links', 'images', 'technicalSeo'];
const sectionLabels = ['Title Tag', 'Meta Description', 'Headings', 'Content Quality', 'Links', 'Images', 'Technical SEO'];
sections.forEach((s, i) => {
  const data = ai[s];
  if (data) {
    const scoreColor = (data.score || 0) >= 80 ? '#28a745' : (data.score || 0) >= 60 ? '#ffc107' : '#dc3545';
    html += '<h3>' + sectionLabels[i] + ' <span style="color: ' + scoreColor + ';">' + (data.score || 'N/A') + '/100</span></h3>';
    if (data.current) html += '<p><strong>Current:</strong> ' + data.current + '</p>';
    if (data.findings) html += '<p><strong>Findings:</strong> ' + data.findings + '</p>';
    if (data.recommendation) html += '<p><strong>Recommendation:</strong> ' + data.recommendation + '</p>';
  }
});

if (ai.topIssues && ai.topIssues.length > 0) {
  html += '<h2 style="color: #dc3545;">Top Issues</h2><ol>';
  ai.topIssues.forEach(issue => { html += '<li>' + issue + '</li>'; });
  html += '</ol>';
}

if (ai.quickWins && ai.quickWins.length > 0) {
  html += '<h2 style="color: #28a745;">Quick Wins</h2><ol>';
  ai.quickWins.forEach(win => { html += '<li>' + win + '</li>'; });
  html += '</ol>';
}

html += '</div>';

return { html, date, overallScore: ai.overallScore || 0, grade: ai.grade || 'N/A' };
